import '@/checkout/containers/MergedCartBanner/MergedCartBanner.css';
import {
  AlertBanner,
  AlertBannerProps,
  Icon,
} from '@adobe-commerce/elsie/components';
import { Text, useText } from '@adobe-commerce/elsie/i18n';
import { InfoFilled } from '@adobe-commerce/elsie/icons';
import { classes } from '@adobe-commerce/elsie/lib/classes';
import { Container } from '@adobe-commerce/elsie/lib/types';
import { events } from '@adobe-commerce/event-bus';
import { useCallback, useEffect, useState } from 'preact/hooks';

export interface MergedCartBannerProps extends AlertBannerProps {
  active?: boolean;
}

export const MergedCartBanner: Container<MergedCartBannerProps> = ({
  className,
  initialData,
  active = true,
  ...props
}) => {
  const [totalMergedItems, setTotalMergedItems] = useState(0);

  const translations = useText({
    mergedCartBannerItems: (
      <Text
        fields={{
          count: totalMergedItems,
        }}
        id="Checkout.MergedCartBanner.items"
        plural={totalMergedItems}
      />
    ),
  });

  const onDismiss = () => {
    setTotalMergedItems(0);
  };

  const handleCartMerged = useCallback((data: { oldCartItems: any[] }) => {
    const oldCartItems = data?.oldCartItems?.reduce(
      (acc, item) => acc + item.quantity,
      0
    );

    if (oldCartItems > 0) {
      setTotalMergedItems(oldCartItems);
    }
  }, []);

  useEffect(() => {
    if (!active) return;

    const onCartMerged = events.on('cart/merged', handleCartMerged, {
      eager: true,
    });
    return () => {
      onCartMerged?.off();
    };
  }, [active, handleCartMerged]);

  useEffect(() => {
    if (!active) return;

    const onCartReset = events.on(
      'cart/reset',
      () => {
        setTotalMergedItems(0);
      },
      {
        eager: false,
      }
    );
    return () => {
      onCartReset?.off();
    };
  }, [active]);

  if (!active || !totalMergedItems) return null;

  return (
    <AlertBanner
      {...props}
      aria-label={translations.mergedCartBannerItems}
      className={classes(['checkout__banner', className])}
      data-testid="merged-cart-banner"
      icon={<Icon source={InfoFilled} />}
      message={<span>{translations.mergedCartBannerItems}</span>}
      variant="neutral"
      onDismiss={onDismiss}
    />
  );
};
